    public Object parseTicker(Object ticker, Object... optionalArgs)
    {
        // {
        //     "DayHighestPrice":43489.49,
        //     "DayLowestPrice":41998.32,
        //     "DayAvgPrice":42743.9,
        //     "DayVolumeXbt":44.54515625000,
        //     "DayVolumeXbtInSecondaryCurrrency":0.12209818,
        //     "CurrentLowestOfferPrice":43619.64,
        //     "CurrentHighestBidPrice":43153.58,
        //     "LastPrice":43378.43,
        //     "PrimaryCurrencyCode":"Xbt",
        //     "SecondaryCurrencyCode":"Usd",
        //     "CreatedTimestampUtc":"2022-01-14T22:52:29.5029223Z"
        // }
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.parse8601(this.safeString(ticker, "CreatedTimestampUtc"));
        Object baseId = this.safeString(ticker, "PrimaryCurrencyCode");
        Object quoteId = this.safeString(ticker, "SecondaryCurrencyCode");
        Object defaultMarketId = null;
        if (Helpers.isTrue(Helpers.isTrue((!Helpers.isEqual(baseId, null))) && Helpers.isTrue((!Helpers.isEqual(quoteId, null)))))
        {
            defaultMarketId = Helpers.add(Helpers.add(baseId, "/"), quoteId);
        }
        market = this.safeMarket(defaultMarketId, market, "/");
        Object symbol = Helpers.GetValue(market, "symbol");
        Object last = this.safeString(ticker, "LastPrice");
        return this.safeTicker(new java.util.HashMap<String, Object>() {{
            put( "symbol", symbol );
            put( "timestamp", timestamp );
            put( "datetime", IndependentreserveCore.this.iso8601(timestamp) );
            put( "high", IndependentreserveCore.this.safeString(ticker, "DayHighestPrice") );
            put( "low", IndependentreserveCore.this.safeString(ticker, "DayLowestPrice") );
            put( "bid", IndependentreserveCore.this.safeString(ticker, "CurrentHighestBidPrice") );
            put( "bidVolume", null );
            put( "ask", IndependentreserveCore.this.safeString(ticker, "CurrentLowestOfferPrice") );
            put( "askVolume", null );
            put( "vwap", null );
            put( "open", null );
            put( "close", last );
            put( "last", last );
            put( "previousClose", null );
            put( "change", null );
            put( "percentage", null );
            put( "average", IndependentreserveCore.this.safeString(ticker, "DayAvgPrice") );
            put( "baseVolume", IndependentreserveCore.this.safeString(ticker, "DayVolumeXbtInSecondaryCurrrency") );
            put( "quoteVolume", null );
            put( "info", ticker );
        }}, market);
    }

