    /**
     * @method
     * @name independentreserve#fetchTradingFees
     * @description fetch the trading fees for multiple markets
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a dictionary of [fee structures]{@link https://docs.ccxt.com/?id=fee-structure} indexed by market symbols
     */
    public java.util.concurrent.CompletableFuture<Object> fetchTradingFees(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object response = (this.privatePostGetBrokerageFees(parameters)).join();
            //
            //     [
            //         {
            //             "CurrencyCode": "Xbt",
            //             "Fee": 0.005
            //         }
            //         ...
            //     ]
            //
            Object fees = new java.util.HashMap<String, Object>() {{}};
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(response)); i++)
            {
                Object fee = Helpers.GetValue(response, i);
                Object currencyId = this.safeString(fee, "CurrencyCode");
                Object code = this.safeCurrencyCode(currencyId);
                Object tradingFee = this.safeNumber(fee, "Fee");
                Helpers.addElementToObject(fees, code, new java.util.HashMap<String, Object>() {{
        put( "info", fee );
        put( "fee", tradingFee );
    }});
            }
            Object result = new java.util.HashMap<String, Object>() {{}};
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(this.symbols)); i++)
            {
                Object symbol = Helpers.GetValue(this.symbols, i);
                Object market = this.market(symbol);
                Object fee = this.safeValue(fees, Helpers.GetValue(market, "base"), new java.util.HashMap<String, Object>() {{}});
                Helpers.addElementToObject(result, symbol, new java.util.HashMap<String, Object>() {{
        put( "info", IndependentreserveCore.this.safeValue(fee, "info") );
        put( "symbol", symbol );
        put( "maker", IndependentreserveCore.this.safeNumber(fee, "fee") );
        put( "taker", IndependentreserveCore.this.safeNumber(fee, "fee") );
        put( "percentage", true );
        put( "tierBased", true );
    }});
            }
            return result;
        });

    }

    /**
     * @method
     * @name independentreserve#createOrder
     * @description create a trade order
     * @param {string} symbol unified symbol of the market to create an order in
     * @param {string} type 'market' or 'limit'
     * @param {string} side 'buy' or 'sell'
     * @param {float} amount how much of currency you want to trade in units of base currency
     * @param {float} [price] the price at which the order is to be fulfilled, in units of the quote currency, ignored in market orders
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} an [order structure]{@link https://docs.ccxt.com/?id=order-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> createOrder(Object symbol, Object type2, Object side2, Object amount, Object... optionalArgs)
    {
        final Object type3 = type2;
        final Object side3 = side2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object type = type3;
            Object side = side3;
            Object price = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object market = this.market(symbol);
            Object orderType = this.capitalize(type);
            orderType = Helpers.add(orderType, ((Helpers.isTrue((Helpers.isEqual(side, "sell"))))) ? "Offer" : "Bid");
            final Object finalOrderType = orderType;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "primaryCurrencyCode", Helpers.GetValue(market, "baseId") );
                put( "secondaryCurrencyCode", Helpers.GetValue(market, "quoteId") );
                put( "orderType", finalOrderType );
            }};
            Object response = null;
            Helpers.addElementToObject(request, "volume", amount);
            if (Helpers.isTrue(Helpers.isEqual(type, "limit")))
            {
                Helpers.addElementToObject(request, "price", price);
                response = (this.privatePostPlaceLimitOrder(this.extend(request, parameters))).join();
            } else
            {
                response = (this.privatePostPlaceMarketOrder(this.extend(request, parameters))).join();
            }
            final Object finalResponse = response;
            return this.safeOrder(new java.util.HashMap<String, Object>() {{
                put( "info", finalResponse );
                put( "id", Helpers.GetValue(finalResponse, "OrderGuid") );
            }}, market);
        });

    }

